var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"11:32 ARC-KP1 \\n어느 폐건물 \\n<color=#ff3636>사건 발생</color> 11시간 경과","JPN":"11:32 ARC-KP1 \\nとある廃墟\\n<color=#ff3636>事件発生から</color>11時間経過","ENG":"11:32 ARC-KP1\\nUnknown Abandoned Building\\n11 hours after <color=#ff3636>Incident</color>","TWN":"11:32 ARC-KP1\\n某個廢棄建築\\n<color=#ff3636>事件發生</color>經過11小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하아……. 하아……. 숨이 찰 때까지 달려 본 건 처음이에요.","JPN":"はあ……はあ……息切れするほど走ったのは初めてです。","ENG":"*Huff... Huff...* I don’t think I’ve ever run so much in my life.","TWN":"呼呼……呼呼……我還是第一次跑到這樣上氣不接下氣呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"감찰과는 무사히 따돌렸습니다. 두 사람이 제 역할을 해 준 모양이네요.","JPN":"監察課の追跡は無事かわしました。あの二人が役割を果たしてくれたみたいですね。","ENG":"We've successfully gotten the Investigation goons off our tail. Looks like those two are fending them off pretty well.","TWN":"監察科沒有追上來，看來他們兩個的策略成功。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런데 여기는…… 어디죠?","JPN":"ところで、ここは……どこでしょう？","ENG":"Um, so... Where are we?","TWN":"不過……這裡是哪裡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"제가 평소에 만들어 둔 아지트입니다.","JPN":"私が以前から確保しておいたアジトです。","ENG":"This is a hideout I made during my free time.","TWN":"這是我的秘密基地。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"잠시 쉬죠. 감찰과 무전을 도청 중이니 접근하면 바로 알 수 있어요.","JPN":"少し休みましょう。監察課の無線を盗聴しているので、\\n近づかれたらすぐにわかるはずです。","ENG":"Let’s rest here. I’m listening in on their radio, so we’ll know if they’re close.","TWN":"老大你先休息一下，我正在竊聽監察科的無線電，萬一他們找到這裡來，我馬上就可以知道。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 네. 고마워요, 초원 씨.","JPN":"はい。ありがとうございます、ナオさん。","ENG":"Okay. Thank you, Chowon.","TWN":"好的，謝謝你，初源。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"실장님과는 통화하셨나요? 위기대응 부서로 이관되기 전에 어서 대처해야 할 텐데요.","JPN":"室長とは連絡がとれましたか？\\n危機管理部に移管される前に、急いで対処しなければなりません。","ENG":"Have you called Chief yet? We need to resolve this before it’s transferred to the Crisis Response Department.","TWN":"你和室長通過電話了嗎？必須在移交給危機處理小組前，趕快處理好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"오는 동안 계속 연락해 봤는데 응답이 없어요.","JPN":"来る途中もずっと連絡してみましたが、応答がありません。","ENG":"I’ve been trying, but she’s not answering.","TWN":"我在來的路上有一直試著聯絡李珍姐，但都聯絡不上。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지금까지 이런 적은 없었는데…….","JPN":"今までこんなことは無かったのに……","ENG":"This hasn’t happened before...","TWN":"她從來沒有這樣過……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아쉽게도 그건 좀 어려울 것 같군요.","JPN":"……残念ですが、それはちょっと難しいかと。","ENG":"...I’m afraid that might be difficult.","TWN":"……很抱歉，可能沒辦法。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"연회가 끝나고 부회장님께서 따로 호출하셔서요.","JPN":"宴会の後は、副会長に呼び出されていますので。","ENG":"The Vice Chairman wants to see me after the banquet is over.","TWN":"宴會結束後，副會長另外有事找我。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니는 연회 이후에 숙부님을 만나러 간다고 하셨어요.","JPN":"ホノカさんは宴会の後、叔父様に会うと言っていました。","ENG":"Jin told me she was meeting the Vice Chairman after the banquet.","TWN":"李珍姐說她宴會結束後要去找叔叔。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 숙부님이 정말 돌아가셨다면…….","JPN":"叔父様が本当に亡くなったのなら……","ENG":"But if Uncle is really dead...","TWN":"可是叔叔已經死了……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"같이 있던 이진 언니까지 무슨 일에 휘말렸을지도 몰라요.","JPN":"一緒にいたホノカさんまで巻き込まれたのかもしれません。","ENG":"Jin might also be in some kind of trouble.","TWN":"那李珍姐會不會也發生什麼事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……그럴 수도 있겠군요.","JPN":"……その可能性はありますね。","ENG":"You might be right.","TWN":"……也是不無可能。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니, 무사하셨으면 좋겠는데…….","JPN":"ホノカさん、無事でいてください……","ENG":"I hope Jin’s safe...","TWN":"希望她沒事……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더만큼은 아니더라도 충분히 유능한 사람입니다. 지금은 본인 앞가림부터 신경 쓰세요.","JPN":"リーダーほどではなくとも、十分優秀な人です。\\n今は自分のことを優先してください。","ENG":"She’s not you, Leader, but she’s still able to take care of herself. Right now, let’s focus on us.","TWN":"雖然室長沒有老大厲害，但能力也是不差的。現在還是先專注在自己眼前的問題上吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"뭔가 짐작 가는 건 없으신가요?","JPN":"何か心当たりはありませんか？","ENG":"Is there anyone who you think could’ve done this?","TWN":"你有想到什麼嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"부회장을 살해하고, 리더에게 누명을 씌울 만한 <color=#ffd34c>범인</color>에 대해서.","JPN":"副会長を殺害して、リーダーに濡れ衣を着せるような<color=#ffd34c>犯人</color>について。","ENG":"I mean, about the <color=#ffd34c>suspect</color> who murdered the Vice Chairman and is now attempting to frame you.","TWN":"誰會殺害副會長，還把罪名賴給你，真正的<color=#ffd34c>犯人</color>到底是誰？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……글쎄요. 짚이는 건 없어요.","JPN":"……そうですね。心当たりはありません。","ENG":"Nobody comes to mind right now...","TWN":"……這個嘛，我目前還沒什麼想法。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"회장직을 노린 분쟁이라면 어떤가요?","JPN":"会長の座を狙っての犯行の可能性は？","ENG":"Could it be someone trying to claim the role of President of the Group?","TWN":"那還是有誰覬覦會長的位置？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"숙부님은 곧 회장 권한대행에서 물러나실 예정이었어요.","JPN":"叔父様はまもなく会長代行から退く予定でした。","ENG":"Uncle was about to step down from acting President.","TWN":"叔叔馬上就要卸除會長代理人的職務，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"범인의 목적이 회장직이라면 이런 시기에 숙부님을 해코지하는 건 이상해요.","JPN":"犯人の目的が会長職なら、こんな時期に叔父様を狙うのは不自然です。","ENG":"It wouldn’t make sense to make Uncle their target.","TWN":"犯人的目的若是會長的位置，那選在這種時候對叔叔下手不是很奇怪嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"곧 물러날 부회장보다 다른 유력 후보들을 노리는 게 더 득이 된다는 말씀이군요.","JPN":"まもなく退く予定の副会長よりも、他の有力候補たちを狙ったほうが犯人にとって得だということですね？","ENG":"So it would’ve been more sensible to target the other candidates, rather than your uncle...","TWN":"老大的意思是，犯人下手的對象應該是其他有力的候選人，而不是快要退位的副會長對吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"게다가……. 숙부님은 노는 걸 싫어하셔서 매일 일만 하셨거든요.","JPN":"それに……叔父様は娯楽を嫌って、毎日仕事ばかりされていました。","ENG":"Besides... Uncle hated leisure and worked all day.","TWN":"而且……叔叔是工作狂，每天都埋首於工作。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"1년에 한 번뿐인 혁신의 밤이 아니었다면 그런 자리에 나오진 않으셨을 거예요.","JPN":"年に一度の『革新の夕べ』じゃなかったら、あんな場に出られることはなかったでしょう。","ENG":"If it was any other event rather than the annual banquet, he would’ve never even considered participating.","TWN":"要不是革新之夜1年只有1次，叔叔也不可能會出現在那種場合。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"부회장의 동향을 알 만큼 그룹의 내부 사정에 밝으면서, 회장직이 아니라 다른 목적을 가진 인물…….","JPN":"副会長の動向を知っているほどグループの内部事情に詳しく、\\n会長職以外の目的を持った人物……","ENG":"That means this person is familiar with the Vice Chairman and the company, but has other goals than becoming President...","TWN":"意思犯人對於公司內部的事很熟悉，甚至知道副會長的行程，而且他的目的不是會長的位置……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그자가 범인이라는 말씀이군요.","JPN":"その人物が犯人ということですね。","ENG":"So, that’s who we should be looking for.","TWN":"而是另有所圖。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 하지만 이것만 가지고는 범인이 누군지 알기 어렵겠네요.","JPN":"はい。ですが、これだけでは犯人を割り出すのは難しいですね。","ENG":"Yes. However, based on this alone, it is difficult to determine who the culprit is.","TWN":"沒錯，不過光憑這些推測，還是無法得知犯人是誰。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"거기 누구죠? 살살 쏠 생각 없으니 신원을 밝히세요.","JPN":"そこにいるのは誰ですか？　手加減するつもりはないので、名乗り出てください。","ENG":"Who’s there?! Identify yourself, or else...!","TWN":"誰在那裡？不想變蜂窩的話，就趕快現身！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠시만요, 초원 씨. 총을 겨누지 말아 주세요.","JPN":"ちょっと待ってください、ナオさん。銃口を向けないでください。","ENG":"Chowon, please lower your gun.","TWN":"等等，初源，把槍放下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨……. 여기 계셨군요.","JPN":"お嬢様……ここにいらっしゃったのですね。","ENG":"Miss Jia... Thank goodness I found you.","TWN":"小姐……原來你在這裡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"통화 기록으로 동선을 파악하느라…… ","JPN":"通話記録から動線をたどっていましたので……","ENG":"I was tracking you from your call signal and...","TWN":"我照著電話記錄的定位找到…… "},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"큭!!","JPN":"くっ！！","ENG":"Ngh!","TWN":"唔！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니!","JPN":"ホノカさん！","ENG":"Jin!","TWN":"李珍姐！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"세상에, 피가 많이 나잖아요! 금방 지혈해 드릴 테니까 조금만 참으세요!","JPN":"ひどい出血じゃないですか！\\nすぐに止血しますので、少しだけ我慢してください！","ENG":"Oh my, you’re bleeding! Hold on! I’ll make it stop!","TWN":"怎麼會這樣！你流好多血！我馬上幫你止血，你忍耐一下！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어, 언니……? 왜 제 손을 뿌리치세요……?","JPN":"ホ、ホノカさん……？　どうして私の手を振り払うのですか……？","ENG":"J-Jin...? Why are you pushing my hand away…?","TWN":"李珍姐……？為什麼甩開我的手……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……가까이 오지 마세요, 아가씨. 지금은.","JPN":"……今は私に近づかないでください、お嬢様。","ENG":"...Don’t come any closer, Miss. At least for now...","TWN":"……小姐，你現在別靠近我！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"왜 그러죠, 실장님? 그 패잔병 같은 꼴은 또 뭐고요?","JPN":"室長、どうしましたか？　その敗残兵のような姿はどういうことですか？","ENG":"Chief, what’s going on? And why are you so beat up?","TWN":"室長，你怎麼了？還有你怎麼會傷成這樣？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"지금은 설명드릴 시간이 없어요. 저는 그저…….","JPN":"今は説明する時間がありません。私はただ……","ENG":"There’s no time to explain. I just...","TWN":"我現在沒時間跟你們解釋這麼多，我……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현장 직원들에게 알린다. 도주자 발견.</color>","JPN":"<color=#ffd34c>現場のメンバーに告げる。逃走者を発見。</color>","ENG":"<color=#ffd34c>Reporting all agents. Fugitives located.</color>","TWN":"<color=#ffd34c>現場人員聽著，發現逃犯。</color>"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>상대는 무장한 카운터 둘. 포위를 유지한 상태로 대기하라. 반복한다…….</color>","JPN":"<color=#ffd34c>相手は武装したカウンター2名。包囲状態を維持したまま待機せよ。繰り返す……</color>","ENG":"<color=#ffd34c>Both are armed Counters. Do not engage and wait for further orders. I repeat...</color>","TWN":"<color=#ffd34c>對方是2名武裝制裁者，保持包圍狀態。再重複一次……</color>"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"이 무전은…… 실장님, 설마?","JPN":"この無線は……室長、まさか？","ENG":"That radio... It can't be!","TWN":"這個無線電是……室長，難道是你？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"오해입니다! 제가 부른 게 아니에요!","JPN":"誤解です！　私が呼んだのではありません！","ENG":"It wasn’t me! I didn’t call them in!","TWN":"不是的！我沒有通報他們！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"지금 같은 상황에서 그런 궁한 변명을 믿으란 건가요?","JPN":"この状況でそんな苦しい言い訳を信じろと？","ENG":"Do you think we’re that stupid to fall for that?","TWN":"事實擺在眼前，你覺得我有可能相信你嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"더 늦기 전에 이만 이동하죠, 리더.","JPN":"手遅れになる前に移動しましょう、リーダー。","ENG":"Leader, we have to get moving before it’s too late.","TWN":"老大，我們快逃吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"감찰과와 내통할 가능성이 있는 한, 실장은 더 이상 믿을 수 없습니다.","JPN":"監察課と内通している可能性がある以上、室長はもう信用できません。","ENG":"The Chief can’t be trusted if there’s the slightest possibility that she’s working with Investigations.","TWN":"室長很可能和監察科串通，我們不能再相信她了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"큭……?!","JPN":"くっ……！？","ENG":"Ugh...!","TWN":"唔……？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"후후. 어딜 가려고, 이 악의 졸개.","JPN":"フフ。どこに行くんだい、この悪の手下め。","ENG":"Fu fu. Where do you think you’re going, evil doer?","TWN":"嘿嘿，想逃！你這個壞蛋！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"추적자란 이름이 허울뿐이라고 착각했다면 큰 오산이야.","JPN":"追跡者というのが名前だけだと勘違いしていたなら、大きな間違いだよ。","ENG":"If you thought my name was just for show, you clearly made a big mistake.","TWN":"你以為追擊者這個名字只是好聽而已嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……당신이 여기 있다는 건, 우리 쪽 짐덩이 둘은 이미 당했다는 뜻이군요.","JPN":"……あなたがここにいるということは、あの二人はやられてしまったようですね。","ENG":"If you’re here... That means our two knuckleheads are...","TWN":"……你會出現在這裡，就表示我們那兩個拖油瓶已經遭殃囉？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"후후, 바로 그렇지!","JPN":"フフフ、そのとおりだよ！","ENG":"Fu fu. That’s right!","TWN":"嘿嘿，完全正確！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"기대도 안 했는데 역시나네요. 죽어서 인건비라도 아끼게 되었으니 이득일까요.","JPN":"期待はしていませんでしたが、そうですか。\\n死んでくれたおかげで人件費を節約できるのはよかったと言いましょうか。","ENG":"I knew I couldn’t rely on them. But if they're no longer alive, at least we'll save some money by not having to pay them.","TWN":"原本是不抱期待的，沒想到有兩下子嘛。他們死掉的話，可以省一些人事成本，這樣算是好事嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"안 죽였어! 아무리 악의 졸개라지만 너무 매정한 거 아냐?!","JPN":"殺してないよ！　いくら悪の手下とはいえ、あいつらに冷たすぎない！？","ENG":"I didn’t kill them! I know you’re evil, but I didn’t know you’d be that cold!","TWN":"我沒殺他們！就算你是罪犯的跟班，說這種話未免也太冷血？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"퇴로는 이미 차단됐다! 너희들도 순순히 붙잡히는 게 좋을 거야!","JPN":"退路はすでに塞いだ！　お前たちも大人しく降参したほうが良いよ！","ENG":"We have you surrounded! Surrender now, if you know what’s best for you!","TWN":"你們逃不掉的！乖乖地束手就擒吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……라파엘라 씨라고 하셨죠?","JPN":"……ラファエラさんとおっしゃいましたね？","ENG":"Raphaela, was it?","TWN":"……你說你叫拉菲樂對吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여기 이진 언니는 돌아가신 숙부님과 사고 당시에 동행하셨던 분이에요.","JPN":"こちらのシノザキ・ホノカさんは事故当時、亡くなった叔父様に同行していた方です。","ENG":"This is Jin. She was with the Vice Chairman on the night of the incident.","TWN":"這位是李珍姐，事發當時她和叔叔在一起，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희들을 붙잡기 전에 저 분 이야기를 들어 볼 수 없을까요?","JPN":"私たちを連行する前に、この方のお話を聞いていただけませんか？","ENG":"Do you think we could listen to what she has to say, before you take us away?","TWN":"在抓我們之前，是否可以先聽聽她的說法呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"으음…….","JPN":"うむ……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이사회 분들이 라파엘라 씨에게 상대가 말할 기회도 주지 말고 붙잡아 오라던가요?","JPN":"ラファエラさんは理事会の皆さんに、相手の弁明も聞かずに問答無用で捕まえてこいと言われたのですか？","ENG":"Did the board of directors order you to bring us in, without giving us a chance to tell our side of the story?","TWN":"還是董事會的人有交代你，不准對方說話，只管把人抓回去？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"아, 아냐! 나 역시 파사의 길을 걷는 몸! 다른 사람 말에 흔들리진 않는걸! ","JPN":"い、いや！　私だって破邪の道を歩む者！　他人の言葉に振り回されたりなんてしないから！","ENG":"N-no! Eradicating evil is the only path I know! What others say doesn't sway me!","TWN":"才…才沒有！我可是走在破邪之路的人！才不會受其他人的言語左右！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"어쨌든, 뭐, 좋아. 증인은 많으면 많을수록 좋으니까.","JPN":"とにかく、まあいいよ。証人は多ければ多いほど良いからね。","ENG":"But, all right. It’s better to have more witnesses.","TWN":"好吧！反正證人越多越好！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말요? 바쁘실 텐데 고마워요. 라파엘라 씨.","JPN":"本当ですか？　お忙しいところ、ありがとうございます。ラファエラさん。","ENG":"Really? Thank you, Raphaela.","TWN":"真的嗎？拉菲樂，謝謝你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더, 지금은 정에 매달려 그런 한가한 소리나 할 때가…….","JPN":"リーダー、そんな悠長なことを言っている場合では……","ENG":"Leader, now’s not the time to be sympathetic to others...","TWN":"老大，現在不是感情用事的時候……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"부탁해요, 초원 씨. 지금이 아니면 들을 수 없을지도 몰라요.","JPN":"お願いします、ナオさん。今じゃなければ聞けないかもしれません。","ENG":"Chowon, this might be the only time to hear what really happened.","TWN":"拜託了，初源，現在不聽她說的話，我怕以後沒機會。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"얘기해 주세요, 언니. 어젯밤 일에 대해서.","JPN":"ホノカさん、お聞かせください。昨夜起きたことについて。","ENG":"Jin... Please tell us what happened that night.","TWN":"李珍姐，請你說明一下昨天晚上的事嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};